using System;
using System.Collections.Generic;
using System.Linq.Expressions;
using System.Reflection;
using DevExpress.Xpo;
using TIG.TotalLink.Shared.DataModel.Core.Attribute;
using TIG.TotalLink.Shared.DataModel.Core.Extension;
using TIG.TotalLink.Shared.DataModel.Core.Helper;
using TIG.TotalLink.Shared.DataModel.Core.Interface;

namespace TIG.TotalLink.Shared.DataModel.Core
{
    /// <summary>
    /// Base data model object which provides an autogenerated guid key mapped to the 'Oid' field.
    /// </summary>
    [NonPersistent]
    [Serializable]
    public abstract class DataObjectBase : XPCustomObject, IAliasedDataObject
    {
        #region Private Fields

        private Guid _oid = Guid.Empty;
        private readonly PropertyInfo _defaultProperty;
        private readonly Dictionary<string, object> _aliasValues = new Dictionary<string, object>();
        private readonly List<PropertyInfo> _modifiedParentProperties = new List<PropertyInfo>();
        private bool _parentsModified;

        #endregion


        #region Constructors

        protected DataObjectBase(Session session)
            : base(session)
        {
            // Attempt to get the default property using the DisplayFieldAttribute
            var type = GetType();
            var displayFieldAttribute = type.GetCustomAttribute<DisplayFieldAttribute>(true);
            if (displayFieldAttribute != null)
            {
                _defaultProperty = type.GetProperty(displayFieldAttribute.FieldName, BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic);
            }

            // Store any parent properties that should be marked as modified when this object is modified
            var modifiesParentAttributes = type.GetCustomAttributes<ModifiesParentAttribute>(true);
            foreach (var modifiesParentAttribute in modifiesParentAttributes)
            {
                var property = type.GetProperty(modifiesParentAttribute.ParentPropertyName, BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic);
                if (property != null)
                    _modifiedParentProperties.Add(property);
            }
        }

        protected DataObjectBase()
            : this(Session.DefaultSession)
        {
        }

        #endregion


        #region Public Properties

        [Persistent("OID")]
        [Key(true)]
        public virtual Guid Oid
        {
            get { return _oid; }
            set
            {
                SetPropertyValue("Oid", ref _oid, value);
            }
        }

        /// <summary>
        /// Indicates if this data object exists in the local session only.
        /// </summary>
        [NonPersistent]
        public bool IsLocalOnly
        {
            get
            {
                try
                {
                    // If the data object exists in the default session, then the object is local
                    return ReferenceEquals(Session, XpoDefault.Session);
                }
                catch (ObjectDisposedException)
                {
                    // If the session is disposed, then we assume the object has been loaded from the db
                    return false;
                }
            }
        }

        #endregion


        #region Public Methods

        /// <summary>
        /// Sets a property using an expression for the property name.
        /// Internally this method uses the PersistentBase.SetPropertyValue method.
        /// </summary>
        /// <typeparam name="T">The type of the property value.</typeparam>
        /// <param name="storage">Local field where the value will be stored.</param>
        /// <param name="value">The new value for the property.</param>
        /// <param name="expression">An expression that specifies the property name.</param>
        /// <returns>True if the property was updated; otherwise false.</returns>
        protected bool SetProperty<T>(ref T storage, T value, Expression<Func<T>> expression)
        {
            return SetProperty(ref storage, value, expression, null);
        }

        /// <summary>
        /// Sets a property using an expression for the property name.
        /// Internally this method uses the PersistentBase.SetPropertyValue method.
        /// </summary>
        /// <typeparam name="T">The type of the property value.</typeparam>
        /// <param name="storage">Local field where the value will be stored.</param>
        /// <param name="value">The new value for the property.</param>
        /// <param name="expression">An expression that specifies the property name.</param>
        /// <param name="changedCallback">An action to call after the peoperty is updated.</param>
        /// <returns>True if the property was updated; otherwise false.</returns>
        protected bool SetProperty<T>(ref T storage, T value, Expression<Func<T>> expression, Action changedCallback)
        {
            // Get the property name
            var propertyName = GetPropertyName(expression);

            // Set the property value using the base function
            var result = SetPropertyValue(propertyName, ref storage, value);

            // Call the changedCallback, if there is one
            if (result && changedCallback != null)
                changedCallback();

            // Return the result
            return result;
        }

        #endregion


        #region Private Methods

        /// <summary>
        /// Gets a property name from an extension.
        /// </summary>
        /// <typeparam name="T">The type that contains the property.</typeparam>
        /// <param name="expression">An expression that specifies the property name.</param>
        /// <returns>The name of the property.</returns>
        public static string GetPropertyName<T>(Expression<Func<T>> expression)
        {
            // Copied from BindableBase...
            return GetPropertyNameFast((LambdaExpression)expression);
        }

        /// <summary>
        /// Gets a property name from an extension.
        /// </summary>
        /// <param name="expression">An expression that specifies the property name.</param>
        /// <returns>The name of the property.</returns>
        internal static string GetPropertyNameFast(LambdaExpression expression)
        {
            // Copied from BindableBase...
            var memberExpression = expression.Body as MemberExpression;
            if (memberExpression == null)
                throw new ArgumentException("MemberExpression is expected in expression.Body", "expression");
            var member = memberExpression.Member;
            if (member.MemberType == MemberTypes.Field && member.Name != null && member.Name.StartsWith("$VB$Local_"))
                return member.Name.Substring("$VB$Local_".Length);
            return member.Name;
        }

        #endregion


        #region Overrides

        protected override void OnChanged(string propertyName, object oldValue, object newValue)
        {
            base.OnChanged(propertyName, oldValue, newValue);

            // Abort if the object is loading, or parents have already been marked as modified since last save, or the object is only local
            if (IsLoading || _parentsModified || IsLocalOnly)
                return;

            // Mark each relevant parent as modified
            _parentsModified = true;
            foreach (var parentProperty in _modifiedParentProperties)
            {
                // Attempt to get the parent object
                var parent = parentProperty.GetValue(this) as DataObjectBase;
                if (parent == null)
                    continue;

                // Attempt to get the value of the OptimisticLockField
                var optimisticLock = (int?)parent.GetMemberValue("OptimisticLockField");
                if (!optimisticLock.HasValue)
                    continue;

                // Update the OptimisticLockField
                parent.SetMemberValue("OptimisticLockField", optimisticLock.Value + 1);
            }
        }

        protected override void OnSaved()
        {
            base.OnSaved();

            // Object has now been saved so we will need to mark parent modified again if more changes are made
            _parentsModified = false;
        }

        public override string ToString()
        {
            // If a defaultProperty was found...
            if (_defaultProperty != null)
            {
                // If this object is an IReferenceDataObject, and the defaultProperty is named "Reference", return a formatted reference number
                var referenceDataObject = this as IReferenceDataObject;
                if (referenceDataObject != null && _defaultProperty.Name == "Reference")
                    return referenceDataObject.GetFormattedReferenceNumber();

                // Use the value of the property
                var defaultPropertyValue = _defaultProperty.GetValue(this);
                if (defaultPropertyValue != null)
                    return defaultPropertyValue.ToString();
            }

            // Otherwise, use the default base implementation
            return base.ToString();
        }

        #endregion


        #region IAliasedDataObject

        /// <summary>
        /// A dictionary which stores temporary values for aliases on cloned or copied data objects.
        /// </summary>
        [NonPersistent]
        public Dictionary<string, object> AliasValues
        {
            get { return _aliasValues; }
        }

        /// <summary>
        /// Indicates if a temporary alias value is stored for the specified alias.
        /// </summary>
        /// <param name="alias">The AliasFieldMapping to search for.</param>
        /// <returns>True if a temporary value is stored for the specified alias; otherwise false.</returns>
        public bool ContainsAliasValue(AliasedFieldMapping alias)
        {
            return alias != null && AliasValues.ContainsKey(alias.AliasFieldName);
        }

        #endregion
    }
}
